import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.其二：妖刀姬","description":"","frontmatter":{},"headers":[],"relativePath":"5.撰写相关/试卷/2.其二：妖刀姬.md","filePath":"5.撰写相关/试卷/2.其二：妖刀姬.md"}'),s={name:"5.撰写相关/试卷/2.其二：妖刀姬.md"};function _(o,e,d,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"_2-其二-妖刀姬",tabindex:"-1"},[b("2.其二：妖刀姬 "),r("a",{class:"header-anchor",href:"#_2-其二-妖刀姬","aria-label":'Permalink to "2.其二：妖刀姬"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),n('<h1 id="其二-妖刀姬" tabindex="-1">其二：妖刀姬 <a class="header-anchor" href="#其二-妖刀姬" aria-label="Permalink to &quot;其二：妖刀姬&quot;">​</a></h1><p>妖刀姬血统</p><p>D级<br> 不祥之刃<br> 提升先攻<br> 解锁妖刀姬技能树</p><p>C级<br> 禁锢之刃<br> 杀意感知<br> 妖刀姬能够攻击意图，在受到瞄准时可以检定洞察对抗成功准确知道敌人位置并让敌人感知到杀意（攻击检定士气减值）失败则只能得知自身受到其他单位的瞄准瞄准行为</p><p>炎刃:<br> 妖刀姬的武器在出鞘后会附加妖刀姬的妖力，攻击检定＋？附加成攻（火焰伤害）</p><p>B级<br> 妖刀万华<br> 妖刀姬可以用任何刀类武器使用妖刀姬技能树招式<br> 先攻9加骰<br> 嗜血:<br> 你的攻击伤害转化妖气储存在刀上。妖气（沉着＋决心）</p><p>噬魔:武器带有法破特性</p><p>A级<br> 觉醒·妖刀姬<br> 新的战斗轮开始时若你的先攻最高你第一轮拥有两个标准动作<br> 先攻8加骰<br> 先攻高于敌方？时，你每次行动皆可进行两个标准动作<br> 妖刀姬:你与刀合二为一，免疫你持有武器的负面效果</p><p>技能树</p><p>刀袭:<br> 消耗一个整轮动作<br> 妖刀姬以几乎瞬移的速度（移动距离等同于移动速度两倍）移动到敌人面前斩击敌人，敌人在防御时会措手不及。（计算你移动到敌人身边之前直线移动的距离，每1米攻击判定+1DP，并使你基础防御-1最高获得DP为防御或攻击取低）刀袭击杀一个敌人后你仍然可以释放一个刀袭，这次的刀袭保有上一次刀袭加值</p><p>见切<br> 消耗意志和一个反射动作<br> 妖刀令妖刀姬的战斗本能超越人类提前察觉攻击到来<br> 你的先攻大于攻击者可以以一次攻击先于他进行攻击<br> 若你这样做对方需要检定运动_武技＋敏捷进行对抗你的攻击伤害数值，若对抗失败则他的此次攻击行动被打断，并且他需要对抗你的攻击；若对抗成功你们同时受到对方攻击<br> 你感到疲倦，使用见切后下一轮攻击检定与防御检定减少</p><p>一闪<br> 以一次迅捷动作进行一个攻击，攻击检定获得力量减值</p><p>杀念<br> 迅捷动作<br> 周围所有生物（不分敌友）攻击检定和防御检定士气减值<br> 你可以以一个标准动作进行强化，加强技能效果</p><p>穷追不舍<br> 对同一敌方进行三次攻击后，你之后每多进行一次攻击，之后的攻击检定便获得1附加成功</p><p>遁刀术<br> 妖刀姬死亡时会遁入刀中。当敌人对妖刀姬的死亡深信不宜时妖刀姬可以消耗刀中妖力回复生命值（若无妖力值妖刀姬死亡）<br> 若妖刀被捡走，妖刀可以诱惑使用者使用，使用者进行意志对抗妖刀姬的意志，对抗失败使用者将必须使用妖刀作为武器。除妖刀姬外其他人使用妖刀攻击时每次攻击都需要消耗一点意志力池和一点能量，并使妖刀姬获得一点妖气。在使用者能量或意志力池空时妖刀姬可显形进行一次攻击检定（措手不及）</p><p>妖气运用（自由动作）<br> 反补:消耗？点妖气，快速医疗？（？医疗点）<br> 屏障:消耗？点妖力，全伤害吸收？<br> 附魔:消耗？点妖力，攻击检定＋？（火焰伤害）</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',18)])])}const m=a(s,[["render",_]]);export{f as __pageData,m as default};
